var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하늘에서 새하얀 마물들이 내려오고 있어……!","JPN":"そ、空から白い魔物たちが降りて来ている……！","ENG":"Th-there are white monsters coming down from the sky...!","TWN":"哈、哈！天上有雪白的怪物降臨了……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"아니야, 저건 마물이 아니야……!","JPN":"違う、あれは魔物じゃない……！","ENG":"No, those aren't monsters...!","TWN":"不是的，那不是怪物……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"저건 틀림없이 우리를 구원해주기 위해 하늘에서 내려온 천사라고……!","JPN":"あれはきっと私たちを救うために空から降りてきた天使なんだ……！","ENG":"Those are angels that have come down from heaven to save us...!","TWN":"那一定是為了拯救我們從天而降的天使……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"오오! 천사님, 부디 우리의 죄를……!","JPN":"おお！　天使よ、どうか我々の罪を……！","ENG":"Oh, angels! Please forgive our sin–","TWN":"喔喔！天使大人，請寬恕我們的罪過……！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊，哈啊……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"런던의 안개가 붉게 변했어……!","JPN":"ロンドンの霧が赤くなった……！","ENG":"The London fog has turned red...!","TWN":"倫敦的霧變成了紅色……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"최대한 들이마시지 말라고 하고 싶지만……!","JPN":"なるべく吸わないようにと言いたいのだが……！","ENG":"I want to tell them not to breathe it in too much, but...!","TWN":"雖然想說儘量別吸進去……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 뛰고 있으니 별 도리가 없군.","JPN":"こうして走ってたら、どうしようもないな。","ENG":"There is nothing I can do when we are running like this.","TWN":"既然這麼奔跑好像也沒辦法了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"살갗이……!! 피부가 검게 썩어 들어가고 있어……!!","JPN":"皮膚が……！！　皮膚が黒く腐っていく……！！","ENG":"My skin...!! It's rotting black...!!","TWN":"皮膚……！！皮膚正在變黑髮爛……！！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"으아, 으아아아아아……!!","JPN":"う、うわああああ……！！","ENG":"Agh... AAAARGH...!!","TWN":"額啊，額啊啊啊啊……！！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사람들이 마물로 변하고 있어……!","JPN":"人々が魔物になっています……！","ENG":"The people are turning into monsters..!","TWN":"那些人變成怪物了……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"돌아보지 말게, 스완. 계속 뛰는 거야……!!","JPN":"振り返るな、スワン。走り続けるのだ……！！","ENG":"Don't look back, Swan. Just keep running...!!","TWN":"不要回頭，史旺。繼續跑……！！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"마, 마물이……!!","JPN":"ま、魔物が……！！","ENG":"M-monsters...!!","TWN":"怪、怪物……！！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"친구! 여긴 내게 맡기고 어서 가게!","JPN":"友よ！　ここは俺に任せて早く行け！","ENG":"My friend! Leave this place to me and go!","TWN":"朋友！這裡交給我，你快走吧！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왓슨!","JPN":"ワトソン！","ENG":"Watson!","TWN":"華生！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"자네에게는 사명이 있어!","JPN":"君には使命がある！","ENG":"You have a duty!","TWN":"別忘記那個使命！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"줄곧 찾아왔던 그 아이에게 전해야 할 진실이 있지 않은가……!","JPN":"ずっと探していたその子に、伝えないといけない真実があるんだろう……？","ENG":"Don't you have a truth that needs to be told to that girl you've been searching for all this time...?!","TWN":"你不是一直在尋找那個孩子嗎？你應該告訴她全部真相……！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 서두르게!","JPN":"だから急ぐんだ！","ENG":"So, go! Quickly!","TWN":"所以，快點吧！快走！"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……알겠네.","JPN":"……わかった。","ENG":"...All right.","TWN":"……知道了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잊지 말게, 왓슨. 나는 자네의 진정한 벗이라는 것을.","JPN":"忘れるな、ワトソン。私は君の真の友だということを。","ENG":"Don't forget, Watson. I am a true friend of yours.","TWN":"別忘了，華生。我是你真正的朋友……"},"stage":{"bg":"LONDON_VICTORIA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 어디까지 가야 하는 거죠?","JPN":"いったいどこまで行くんですか？","ENG":"How much further do we have to go?","TWN":"我們、我們還要跑多遠？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"조금만 더, 이제 조금만 더 가면 된다네.","JPN":"もう少し、あともう少しだ。","ENG":"Just a little more. We're almost there.","TWN":"快了！再堅持一下，就快到了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"음?","JPN":"あれっ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왜 그러지, 스완?","JPN":"どうした、スワン？","ENG":"What is it, Swan?","TWN":"怎麼了，史旺？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이유는 모르겠지만, 도시를 뒤덮고 있던 붉은 안개가 사라졌어요.","JPN":"理由はわかりませんけど、都市を覆いつくしていた赤い霧が消えました。","ENG":"I don't know, but the red fog that was covering the entire city just vanished.","TWN":"雖然不知道原因，但籠罩城市的紅霧已經消失了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"거대한 하얀 마물도 더는 쫓아오지 않고요. 어쩌면 상황이 호전된 거 아닐까요?","JPN":"巨大な白い魔物ももう追ってきていませんし。もしかしたら状況がよくなったんじゃないですか？","ENG":"And those gigantic white monsters aren't following us anymore. Maybe the situation there has gotten better?","TWN":"巨大的白色怪物也不再追來了。或許情況有所好轉了吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럴 리가 없어. 한 번 임계치에 다다른 세계가…….","JPN":"そんなはずはない。一度臨界値に到達した世界が……","ENG":"That can't be. Once a world reaches its critical point...","TWN":"不可能。已經達到臨界點的世界……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"음? 이건 눈? 이런 날씨에 눈이라면……?","JPN":"ん？　これは雪か？　こんな天気に雪が降るということは……？","ENG":"Hmm? Is this snow? If it is snowing in this weather...","TWN":"嗯？這是雪？這種天氣下竟然會下雪……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"엇? 저것 보세요. 애버라인. 하늘에서……!","JPN":"あっ、あれを見てください、アバーライン。空から……！","ENG":"Oh? Look. Abberline! The sky...!","TWN":"咦？快看那個。艾伯林。天上……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"위를 보면 안 돼……!","JPN":"上を向いてはいけない……！","ENG":"Don't look up...!","TWN":"不要往上看……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병의 악취를 좇아, 불멸의 존재들이 계속해서 몰려드는군.","JPN":"疫病の悪臭を追い、不滅の存在が次々と集っているな。","ENG":"The immortals continue to gather following the stench of the plague.","TWN":"追隨著瘟疫的惡臭，不朽的存在們不斷湧來。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"세계의 단말마에 이끌려, 한때 대적자였던 자들이 모여드는 건 예사롭지 않을지니.","JPN":"世界の断末魔に引かれ、かつて敵対者であった者たちが集うのはただ事ではあるまい。","ENG":"Unusual, however, to see those who were once Antagonists being drawn to the world's end.","TWN":"被世界的末日所吸引，曾經的敵對者們聚集在一起，這一幕非同尋常。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇다면 필히 이곳에 강림하리라…….","JPN":"ならば、きっとここに降臨するであろう……","ENG":"Then, this is where she will descend...","TWN":"那麼必定會降臨到這裡是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온.","JPN":"タギリオン。","ENG":"Thagirion.","TWN":"塔基里翁。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"언니…….","JPN":"お姉ちゃん……","ENG":"My sister...","TWN":"姊姊……"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"저를 위해서, 이 땅에 그 증오스러운 자들의 성흔을 손수 모아주시고.","JPN":"私のために、この地の憎い者たちから聖痕を直接集め、","ENG":"You have gathered all the Stigmatas from the despicable ones of this world just for me.","TWN":"為了我，親手收集了這片土地上那些可憎之人的聖痕。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막에는 스스로의 심장까지 내놓으시다니…….","JPN":"最後には自分の心臓まで捧げてくれるなんて……","ENG":"And lastly, you offered your heart to me...","TWN":"最後竟然連自己的心臟都獻出來了……"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 너무 기쁘답니다.","JPN":"私はとても嬉しいです。","ENG":"I could not be any happier.","TWN":"我真的太高興了。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"언니, 듣고 있나요?","JPN":"お姉ちゃん、聞いていますか？","ENG":"Are you listening?","TWN":"姊姊，你在聽嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"아아, 그렇군요. 이 세계의 언니는 이제 심장이 없으니까…….","JPN":"ああ、そうでした。この世界のお姉ちゃんはもう心臓がありませんでしたね……","ENG":"Oh, right. My sister of this world is without a heart...","TWN":"啊啊，是這樣啊。這個世界的姊姊已經沒有心臟了……"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼, 이 실로 언니의 아픈 곳을 전부 꿰매어 드릴게요.","JPN":"では、この糸でお姉ちゃんの悪いところを全部縫って差し上げましょう。","ENG":"Then, I shall sew your pain with this thread.","TWN":"那麼，我會用這根線把姊姊所有的傷口都縫合起來。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"팔도, 다리도, 심장을 꺼내다 부서진 복장뼈와 열려버린 갈비뼈도 전부 재조립해 드릴게요.","JPN":"腕も足も、心臓を取り出して折れてしまった胸骨と肋骨も、すべて組み直します。","ENG":"I will reassemble your broken arms, legs, heart, and bones.","TWN":"手臂、腿、心臟、破碎的胸骨和敞開的肋骨，我都會重新組裝好。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>그러니까 이제부터 저를 위해 살아주세요, 언니.</color>","JPN":"<color=#ff3636>ですから、これからは私のために生きてください、お姉ちゃん。</color>","ENG":"<color=#ff3636>So now, live only for me, my sister.</color>","TWN":"<color=#ff3636>所以從現在開始，請為我而活吧，姊姊。</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>저만을 바라봐 주시고. 제 말만 들어주세요.</color>","JPN":"<color=#ff3636>私だけを見て、私の話だけを聞いてください。</color>","ENG":"<color=#ff3636>Only look at me and listen to my words.</color>","TWN":"<color=#ff3636>只看著我。只聽我的話。</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>그리고…….</color>","JPN":"<color=#ff3636>そして……</color>","ENG":"<color=#ff3636>And...</color>","TWN":"<color=#ff3636>還有……</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>오직, 저를 위한 현악기가 되어 노래해 주세요.</color>","JPN":"<color=#ff3636>ただ、私だけの弦楽器となって歌ってください。</color>","ENG":"<color=#ff3636>Become my personal string instrument and play me your melody.</color>","TWN":"<color=#ff3636>請成為只為我而歌唱的絃樂器吧。</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"분부대로 하겠나이다. 왕이시여.","JPN":"仰せのままに、王よ。","ENG":"As you command, my queen.","TWN":"遵命，我的王。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아. 이런. 기습을 당해버렸네요.","JPN":"あっ、なんと。不意打ちを食らってしまいました。","ENG":"Oh, no. I am being ambushed.","TWN":"啊啊。是被突襲了。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇다면 예하께서도 이미 와계셨던 모양이로군요.","JPN":"ということは、猊下もすでにお出でになっていたのですね。","ENG":"It seems Her Eminence has already arrived.","TWN":"那麼看來主教已經在這裡了。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"오랜만이네요, 예하. 그간 평안하셨을까요?","JPN":"ご無沙汰しております、猊下。ご機嫌麗しゅうございますか。","ENG":"Long time no see, Your Eminence. How have you been?","TWN":"好久不見了，主教大人。這段時間過得還好嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"의아하군. 타기리온.","JPN":"解せないな、タギリオン。","ENG":"How odd, Thagirion.","TWN":"真令人疑惑。塔基里翁。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"분명, 한 합에 심장까지 꿰뚫었거늘.","JPN":"確か、一気に心臓まで貫いたはずだが。","ENG":"I remember your heart being pierced with one strike.","TWN":"我分明一招就刺穿了心臟。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네놈의 가슴에서는 어떠한 고동도 느껴지지 않는구나. 무슨 일이 있었던 거지?","JPN":"貴様の胸からは鼓動がまったく感じられん。何があったのだ？","ENG":"There is no beating in your chest. How is this possible?","TWN":"你的胸口沒有任何心跳。發生了什麼事？"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그야, 같은 실수를 반복할 수는 없으니까요.","JPN":"それは、同じ過ちを繰り返すわけにはいきませんから。","ENG":"That is because I do not make the same mistake twice.","TWN":"因為，我不會再犯同樣的錯誤了。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"물론 예하께서도 알고 계시니 심장을 노렸겠죠?","JPN":"もちろん、猊下もご存じだったからこそ心臓を狙ったのでしょうね。","ENG":"Of course, you would have targeted my heart as well, so you know.","TWN":"當然，你也知道這點，所以才會瞄準心臟吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>한 번에 끝내지 못하면 뒤는 없다는 걸.</color>","JPN":"<color=#ff3636>一気に終わらせないと、二度目はないということを。</color>","ENG":"<color=#ff3636>That there is no second chance.</color>","TWN":"<color=#ff3636>如果不能一擊制勝，就沒有退路。</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그윽……! 그아아아아아아아아아아악……!!","JPN":"ぐふっ……！　ウワアアアアアアアアア……！！","ENG":"Urgh...! RRRRRRAAAAGH...!!","TWN":"呃……！呃啊啊啊啊啊啊啊啊啊啊……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"한 때, 위대한 정적이라고 불리셨던 분의 비명은 몇 번을 들어도 각별해요.","JPN":"かつて、偉大なる静寂と呼ばれていた方の悲鳴は何度を聞いても格別です。","ENG":"It is a delicacy to hear the screams of someone who was once called the Great Silence.","TWN":"曾經被稱為偉大的靜寂的悲鳴，無論聽到多少次都特別地動人。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 감옥을 입혀 두길 잘했어요. 그 아름다운 목소리가 듣기 좋게 울리네요.","JPN":"その牢獄を着せて正解でした。美しい声が綺麗に響いていますね。","ENG":"It was a wise choice to keep you in that prison. It makes your beautiful voice ring clearer.","TWN":"幸好把你關在了這個牢籠裡。那個美妙的聲音在裡面回蕩得真是好聽。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이대로 핵을 재조립해서, 당신도 <color=#ffd34c>언니</color>로 만들어드리죠.","JPN":"このまま核を組み直して、あなたも<color=#ffd34c>お姉ちゃん</color>のようにして差し上げましょう。","ENG":"Now, I'll reassemble your core and make you a <color=#ffd34c>sister</color> as well.","TWN":"就這樣重新組裝核心，讓你也成為<color=#ffd34c>姊姊</color>吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"크윽!! 네놈 타기리오오오온……!!","JPN":"うぐっ！！　おのれ、タギリオオオオン……！！","ENG":"Urgh!! THAGIRION...!!","TWN":"咳！！塔基里翁翁翁翁……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"다음에는 반드시……!! 이 악순환의 굴레를 끊어 내고, 속죄를 완수할 것이다……!!","JPN":"次は必ず……！！　この悪循環の枷を断ち切り、罪を償う……！！","ENG":"Our next meet...! I shall end this vicious cycle and complete my atonement...!!","TWN":"下一次……！！下一次一定！我一定會打破這個迴圈，完成贖罪……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 속죄라는 말은 질리지도 않으신가요?","JPN":"その償いと言う言葉、飽きないのですか？","ENG":"Don't you get tired of that word, \\"atonement?\\"","TWN":"你不覺得“贖罪”這個詞很無聊嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"왜 모르시는 거죠? 다음을 기약하는 시점에서 이미 당신의 패배랍니다.","JPN":"どうしてわからないのですか？　次を口にしている時点で、すでにあなたの負けなのですよ。","ENG":"Why don't you know? The moment you vow for next time, you have already lost.","TWN":"為什麼不明白呢？在期待下一次的時候，你就已經輸了。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"결국 현실에서 퇴거해버렸군요. 예하.","JPN":"結局現実から退去することとなってしまいましたね。猊下。","ENG":"You have resigned from reality, Your Eminence.","TWN":"最終還是從現世中退卻了呢。主教大人。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하긴, 당신은 줄곧 방관자로 남아있는 게 더 어울릴지도 모르겠네요.","JPN":"まあ、あなたはずっと傍観者のままのほうがお似合いかもしれません。","ENG":"Then again, it might be better for you to remain a bystander.","TWN":"沒錯，你一直作為旁觀者可能更為合適。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"예하가 물러나니, 이젠 같잖은 패배자들이 들러붙는군.","JPN":"猊下がいなくなったら、今度はくだらない負け犬どもね。","ENG":"With Her Eminence's retreat, the insignificant losers are starting to gather.","TWN":"主教退下後，這些可笑的失敗者就纏上來了。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 집념밖에 남지 않은 저 수호자들을 처리하는 것도 이 세계의 규칙이라면 규칙.","JPN":"でも、執念しか残っていないあの守護者たちを処理するのもこの世界の規則。","ENG":"But dealing with those guardians who have nothing left but their tenacity is also a rule of this world.","TWN":"但是，如果處理那些只剩執念的守護者也是這個世界的規則，那就遵守吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그래요. 새 언니에게 일을 맡겨야겠군요.","JPN":"そうですね。それは新しいお姉ちゃんにお任せしましょう。","ENG":"Yes. I should leave this to my new sister.","TWN":"嗯，我要把這件事交給新的姊姊。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"따르겠습니다.","JPN":"御意。","ENG":"As you wish.","TWN":"遵命。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"무엇이든 말씀하십시오. 왕이시여.","JPN":"何なりとおっしゃってください。王よ。","ENG":"What is it that you command, my queen?","TWN":"你請吩咐，王上。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"태어나려고 하는 자는, 먼저 하나의 세계를 부숴야 한다는 말도 있죠.","JPN":"生まれようとする者は、まずは一つの世界を壊さないといけないという言葉もあるのです。","ENG":"They say the one who wants to be born must first destroy a world first.","TWN":"有人說，想要重生，必須先毀掉一個世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"자아, 그러니 자신의 세계를 마저 부수도록 하세요.","JPN":"さあ、ですからあなた自身の世界を壊してください。","ENG":"Now, I want you to destroy your own world.","TWN":"所以，繼續摧毀你自己的世界吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"심야의 살인마로서 이 세계의 모든 인간을 단 한 사람도 남김없이 전부 찢어 죽이고.","JPN":"深夜の殺人鬼としてこの世界のすべての人間を一人も残さずに裂いて殺し、","ENG":"As the Midnight Killer, kill all the humans and leave no one behind in this world.","TWN":"作為午夜殺人魔，把這個世界上的所有人類撕成碎片，一個不留吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"종극에 이 세계를 저의 클리파 차원으로 예속시키도록 하세요.","JPN":"最後にはこの世界を私のクリファ次元に隷属させなさい。","ENG":"Subjugate the end of this world to my Qlipha Dimension.","TWN":"最終將這個世界，併入我的逆卡巴拉國度。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제가 원래의 힘을 되찾을 수 있도록.","JPN":"私が元の力を取り戻せるように。","ENG":"So that I will regain my original strength.","TWN":"為了讓我找回原本的力量。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"분부대로 하겠나이다.","JPN":"仰せのままに。","ENG":"As you command.","TWN":"遵命。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"……나의 사랑하는 동생이여.","JPN":"……私の愛する妹よ。","ENG":"...My beloved little sister.","TWN":"……我親愛的妹妹。"},"stage":{"bg":"CORRIDOR_09","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};